// ── App initialisation ────────────────────────────────────────────────────────
async function initApp() {
  try {
    // 1. Load menu from Supabase (fall back to DEFAULT_MENU if empty)
    const dbMenu = await loadMenuFromDB();
    _menuCache = (dbMenu && Object.keys(dbMenu).length > 0) ? normaliseMenu(dbMenu) : JSON.parse(JSON.stringify(DEFAULT_MENU));

    // 2. Load today's orders + set next order number
    const [dbOrders, nextNum] = await Promise.all([
      loadOrdersFromDB(),
      getNextOrderNum(),
    ]);
    _ordersCache  = dbOrders;
    _nextNumCache = nextNum;

    // 3. Boot the UI
    MENU = loadMenu();
    currentCat = Object.keys(MENU)[0];
    document.getElementById('filter-date').value = todayStr();
    try{buildCatSidebar();}catch(e){console.error(e);}
    try{renderMenu();}catch(e){console.error(e);}
    try{renderOrder();}catch(e){console.error(e);}
    try{updateOrderNumBadge();}catch(e){}
    try{updateHeaderStats();}catch(e){}

    // 4. Hide loading screen
    const ls = document.getElementById('loading-screen');
    if (ls) ls.style.display = 'none';

    // 5. Show new-order popup
    showNewOrderPopup();
  } catch (err) {
    console.error('initApp failed:', err);
    const ls = document.getElementById('loading-screen');
    if (ls) ls.innerHTML = `<div class="loading-inner"><div class="loading-logo">⚠️</div><div class="loading-title" style="color:#e74c3c">Connection Error</div><div class="loading-sub" style="color:var(--cream-dim)">${err.message}</div></div>`;
  }
}

function normaliseMenu(obj) {
  const out = {};
  for (const [cat, items] of Object.entries(obj)) {
    if (Array.isArray(items))
      out[cat] = items.map(i => typeof i === 'string' ? {n: i} : (i && i.n ? i : {n: String(i)}));
  }
  return Object.keys(out).length > 0 ? out : JSON.parse(JSON.stringify(DEFAULT_MENU));
}

// ── renderHistory override — load from DB on demand ───────────────────────────
// We replace renderHistory to load from DB with filters applied server-side.
async function renderHistoryAsync() {
  const df  = document.getElementById('filter-date').value;
  const tf  = document.getElementById('filter-type').value;
  const nf  = (document.getElementById('filter-name').value || '').trim();

  try {
    const all = await loadOrdersFromDB({
      date: df || undefined,
      type: tf || undefined,
      name: nf || undefined,
    });
    _ordersCache = all;  // keep cache in sync (unfiltered would be better but this is fine for single-user)
    _renderHistoryFromData(all, df);
  } catch (e) {
    console.error('renderHistory:', e);
  }
}

