function exportMenu(){
  const backup={exported:new Date().toISOString(),version:1,menu:MENU};
  const d=new Date();
  const fname="MotivationalMug_Menu_"+d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0")+".json";
  const a=document.createElement("a");
  a.href=URL.createObjectURL(new Blob([JSON.stringify(backup,null,2)],{type:"application/json"}));
  a.download=fname;
  document.body.appendChild(a);a.click();document.body.removeChild(a);
}
function importMenu(input){
  const file=input.files[0];
  if(!file)return;
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const backup=JSON.parse(e.target.result);
      if(!backup.menu||typeof backup.menu!=="object")throw new Error("Invalid menu file.");
      // Migrate items to object format
      const out={};
      for(const[cat,items]of Object.entries(backup.menu)){
        if(Array.isArray(items))out[cat]=items.map(i=>typeof i==="string"?{n:i}:(i&&i.n?i:{n:String(i)}));
      }
      if(Object.keys(out).length===0)throw new Error("No categories found.");
      MENU=out;
      saveMenu(MENU);
      currentCat=Object.keys(MENU)[0];
      buildCatSidebar();renderMenu();renderEditorCats();renderEditorItems();
      alert("Menu restored! "+Object.keys(MENU).length+" categories loaded.");
    }catch(err){
      alert("Could not restore menu: "+err.message);
    }
    input.value="";
  };
  reader.readAsText(file);
}
function resetMenuToDefault(){
  if(!confirm("Reset menu to default? Your custom changes will be lost."))return;
  saveMenuToDB({}).catch(()=>{});
  MENU=JSON.parse(JSON.stringify(DEFAULT_MENU));
  currentCat=Object.keys(MENU)[0];
  buildCatSidebar();renderMenu();
  try{renderEditorCats();}catch(e){}
  alert("Menu reset! All default items restored with pump counts and Love Latte recipe.");
}
