let _menuCache=null;

function saveMenu(m){_menuCache=m;_supabaseSaveMenu(m).catch(e=>console.error("saveMenu:",e));}
function loadOrders(){return _ordersCache;}
function saveOrders(o){_ordersCache=o;_supabaseSaveOrders(o).catch(e=>console.error("saveOrders:",e));}
function loadNextNum(){return _nextNumCache;}
function saveNextNum(n){_nextNumCache=n;bumpOrderNum(n).catch(e=>console.error("saveNextNum:",e));}

async function _supabaseSaveMenu(m){await saveMenuToDB(m);}
async function _supabaseSaveOrders(arr){
  // We don't bulk-replace on every change; individual ops handle inserts/deletes.
  // This is only called for import; for normal ops we use saveOrderToDB/deleteOrderFromDB.
}

let MENU=loadMenu(),currentCat=Object.keys(MENU)[0],orderType="Member",currentOrder=[],celTimeout=null,sortCol="num",sortDir="desc",lastOrder=null,editorCat=null;

function todayStr(){const d=new Date();return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0")}
function fmtDate(s){const[y,m,d]=s.split("-");const mn=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];return mn[+m-1]+" "+parseInt(d)+", "+y}
function esc(s){return String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}
function esc2(s){return String(s||"").replace(/\\/g,"\\\\").replace(/'/g,"\\'")}

