function showView(id,btn){
  document.querySelectorAll(".view").forEach(v=>v.classList.remove("active"));
  document.getElementById("view-"+id).classList.add("active");
  document.querySelectorAll(".nav-tab").forEach(b=>b.classList.remove("active"));
  btn.classList.add("active");
  if(id==="history")renderHistory();
  if(id==="editor")renderEditorCats();
}
function buildCatSidebar(){
  const el=document.getElementById("cats");el.innerHTML="";
  Object.keys(MENU).forEach(cat=>{
    const b=document.createElement("button");
    b.className="cat-btn"+(cat===currentCat?" active":"");
    b.textContent=cat;b.onclick=()=>selectCat(cat);el.appendChild(b);
  });
  if(!MENU[currentCat])currentCat=Object.keys(MENU)[0]||"";
}
function selectCat(cat){
  currentCat=cat;
  document.querySelectorAll(".cat-btn").forEach((b,i)=>b.classList.toggle("active",Object.keys(MENU)[i]===cat));
  renderMenu();
}
function renderMenu(){
  const grid=document.getElementById("menu-grid");grid.innerHTML="";
  if(!currentCat||!MENU[currentCat])return;
  const inO=new Set(currentOrder.map(o=>o.name));
  MENU[currentCat].forEach(item=>{
    const it=mi(item);
    const b=document.createElement("button");
    b.className="menu-item"+(inO.has(it.n)?" in-order":"");
    let lines=[it.n];
    if(it.dq&&it.unit)lines.push(it.dq+" "+it.unit+"s");
    if(it.recipe&&it.recipe.length)lines.push("(recipe ►)");
    b.textContent=lines.join("\n");
    b.onclick=()=>addMenuItemObj(it);
    grid.appendChild(b);
  });
}
function addMenuItemObj(it){
  if(it.special==="cf_flavor"){openCFFlavorPicker();return;}
  if(it.recipe&&it.recipe.length){
    const ex=currentOrder.find(o=>o.name===it.n&&o.recipe);
    if(ex){ex.qty++;}
    else{currentOrder.push({name:it.n,qty:1,cat:currentCat,recipe:it.recipe.map(r=>Object.assign({},r))});}
  } else {
    const dq=it.dq||1;
    const ex=currentOrder.find(o=>o.name===it.n&&!o.recipe);
    if(ex){ex.qty+=1;}
    else{currentOrder.push({name:it.n,qty:dq,unit:it.unit||null,cat:currentCat});}
  }
  renderOrder();renderMenu();
  // Show workflow popup after adding a base drink
  if(BASE_CATS.has(currentCat)){
    openDrinkPopup(it.n, currentCat);
  }
}
function addMenuItem(name){
  const ex=currentOrder.find(o=>o.name===name);
  if(ex){ex.qty++;}
  else{
    const allItems=(MENU[currentCat]||[]).map(mi);
    const found=allItems.find(i=>i.n===name);
    currentOrder.push({name,qty:1,unit:found?found.unit||null:null,cat:currentCat});
  }
  renderOrder();renderMenu();
}
function removeMenuItem(name){
  const ex=currentOrder.find(o=>o.name===name);
  if(!ex)return;
  ex.qty===1?currentOrder=currentOrder.filter(o=>o.name!==name):ex.qty--;
  renderOrder();renderMenu();
}
function clearOrder(){currentOrder=[];document.getElementById("cust-name").value="";renderOrder();renderMenu();}
function setType(t,b){orderType=t;document.querySelectorAll(".type-btn").forEach(x=>x.classList.remove("active"));b.classList.add("active");}
function qtyLabel(item){
  if(item.unit)return item.qty+" "+item.unit+(item.qty!==1?"s":"");
  return String(item.qty);
}
function recipeTag(item){
  if(!item.recipe||!item.recipe.length)return "";
  const parts=item.recipe.map(r=>{
    const q=fmtUnit(r.qty,r.unit)||(r.qty>1?String(r.qty):"");
    return (q?q+" ":"")+r.n;
  }).join(" · ");
  return `<div class="order-recipe">${parts}</div>`;
}
function renderOrder(){
  const el=document.getElementById("order-items"),btn=document.getElementById("complete-btn");
  if(!currentOrder.length){el.innerHTML='<div class="order-empty">Tap items<br>to build order</div>';btn.disabled=true;const pb=document.getElementById("print-complete-btn");if(pb)pb.disabled=true;return;}
  btn.disabled=false;const pcb=document.getElementById("print-complete-btn");if(pcb)pcb.disabled=false;
  const drinks=currentOrder.filter(i=>BASE_CATS.has(i.cat));
  const customs=currentOrder.filter(i=>!BASE_CATS.has(i.cat));
  let out="";
  if(drinks.length){
    out+='<div class="order-section-label">☕ Drinks</div>';
    out+=drinks.map(item=>`<div class="order-item drink-item"><div class="item-name-wrap"><div class="item-name">${esc(item.name)}</div>${recipeTag(item)}</div><div class="qty-wrap"><button class="qty-btn" onclick="removeMenuItem('${esc2(item.name)}')">&#8722;</button><span class="qty-n">${qtyLabel(item)}</span><button class="qty-btn" onclick="addMenuItem('${esc2(item.name)}')">+</button></div></div>`).join("");
  }
  if(customs.length){
    out+='<div class="order-section-label" style="margin-top:6px">✨ Add-ons</div>';
    out+=customs.map(item=>`<div class="order-item addon-item"><div class="item-name-wrap"><div class="item-name addon-name">${esc(item.name)}</div>${recipeTag(item)}</div><div class="qty-wrap"><button class="qty-btn" onclick="removeMenuItem('${esc2(item.name)}')">&#8722;</button><span class="qty-n">${qtyLabel(item)}</span><button class="qty-btn" onclick="addMenuItem('${esc2(item.name)}')">+</button></div></div>`).join("");
  }
  el.innerHTML=out;
}
