function fmtUnit(qty,unit){
  if(!unit)return "";
  // Show short form for pump (3p), full unit for others (10 oz, 1 scoop)
  if(unit==="pump"||unit==="pumps") return qty+"p";
  return qty+" "+unit;
}
function lblItemLine(i){
  if(i.recipe&&i.recipe.length){
    // Each ingredient on its own line so nothing gets cut off
    const parts=i.recipe.map(r=>{
      const q=fmtUnit(r.qty,r.unit)||(r.qty>1?r.qty:"");
      return (q?q+" ":"")+r.n;
    }).join("<br>");
    return `<div class="lbl-drink-item"><b>${i.name}</b><div class="lbl-recipe">${parts}</div></div>`;
  }
  const qstr=i.unit?fmtUnit(i.qty,i.unit):i.qty>1?`${i.qty}×`:"";
  return `<div class="lbl-drink-item">${qstr?`<span class="lbl-drink-qty">${qstr}</span>`:""}${i.name}</div>`;
}
function buildLabelHTML(order){
  const baseItems=(order.items||[]).filter(i=>BASE_CATS.has(i.cat));
  const addonItems=(order.items||[]).filter(i=>!BASE_CATS.has(i.cat));
  const drinkItems=baseItems.map(lblItemLine).join("");
  const addonLines=addonItems.map(i=>{
    if(i.recipe&&i.recipe.length){
      const parts=i.recipe.map(r=>(r.qty?(r.unit==="pump"?r.qty+"p ":fmtUnit(r.qty,r.unit)+" "):"")+r.n).join(", ");
      return `<div class="lbl-addon-line"><b>${i.name}:</b> ${parts}</div>`;
    }
    const q=i.unit?fmtUnit(i.qty,i.unit):(i.qty>1?i.qty+"×":"");
    return `<div class="lbl-addon-line">${q?q+" ":""}${i.name}</div>`;
  }).join("");
  const addonItemsHTML=addonItems.length?
    `<div class="lbl-addons-head">Add-ons &amp; Customizations</div>${addonLines}`:"";
  return `
    <div class="lbl-topbar">
      <img class="lbl-logo-img" src="${LOGO_PRINT}">
      <div class="lbl-title-col">
        <div class="lbl-title">Motivational Mug</div>
        <div class="lbl-subtitle">Duncansville Evangelical Lutheran Church · delcFAM</div>
      </div>
      <div class="lbl-meta-col">
        <div class="lbl-order-num">#${order.num}</div>
        <div class="lbl-meta-small">${order.time} · ${fmtDate(order.date)}</div>
      </div>
    </div>
    ${order.customer?`<div class="lbl-cust">${order.customer}</div>`:`<div class="lbl-nocust">Walk-up order</div>`}

    <div class="lbl-drinks-head">Make This Order:</div>
    <div class="lbl-drinks-grid">${drinkItems}</div>${addonItemsHTML}
    <div class="lbl-footer">Worship · Learn · Serve · delcFAM</div>`;
}
function printLabel(order){
  document.getElementById("print-label").innerHTML=buildLabelHTML(order);
  setTimeout(()=>window.print(),80);
}
