function renderHistory(){
  const all=loadOrders(),df=document.getElementById("filter-date").value,tf=document.getElementById("filter-type").value,nf=(document.getElementById("filter-name").value||"").trim().toLowerCase();
  let f=all.filter(o=>{if(df&&o.date!==df)return false;if(tf&&o.type!==tf)return false;if(nf&&!(o.customer||"").toLowerCase().includes(nf))return false;return true;});
  f.sort((a,b)=>{let av,bv;if(sortCol==="num"){av=a.num;bv=b.num}else if(sortCol==="date"||sortCol==="time"){av=a.date+a.time;bv=b.date+b.time}else if(sortCol==="customer"){av=(a.customer||"").toLowerCase();bv=(b.customer||"").toLowerCase()}else if(sortCol==="drinks"){av=a.drinkCount;bv=b.drinkCount}else{av=a.num;bv=b.num}if(av<bv)return sortDir==="asc"?-1:1;if(av>bv)return sortDir==="asc"?1:-1;return 0;});
  const tots=f.length,drinks=f.reduce((s,o)=>s+o.drinkCount,0),mem=f.filter(o=>o.type==="Member").length,gue=f.filter(o=>o.type==="Guest").length,tog=f.filter(o=>o.type==="ToGo").length,days=new Set(f.map(o=>o.date)).size;
  document.getElementById("hist-summary").innerHTML=`<div class="hsum-card"><div class="hsum-n">${tots}</div><div class="hsum-l">Orders</div></div><div class="hsum-card"><div class="hsum-n">${drinks}</div><div class="hsum-l">Drinks</div></div><div class="hsum-card"><div class="hsum-n">${mem}</div><div class="hsum-l">Members</div></div><div class="hsum-card"><div class="hsum-n">${gue}</div><div class="hsum-l">Guests</div></div><div class="hsum-card"><div class="hsum-n">${tog}</div><div class="hsum-l">To Go</div></div>${!df?`<div class="hsum-card"><div class="hsum-n">${days}</div><div class="hsum-l">Days</div></div>`:""}`;
  const tbody=document.getElementById("history-tbody");
  if(!f.length){tbody.innerHTML=`<tr><td colspan="9" class="no-data">No orders found<br><span style="font-size:.78rem;color:var(--border)">Try a different date or filter</span></td></tr>`;updateSortIcons();return;}
  tbody.innerHTML=f.map(o=>`<tr><td style="color:var(--gold);font-weight:600">#${o.num}</td><td style="white-space:nowrap">${fmtDate(o.date)}</td><td style="white-space:nowrap;color:var(--muted)">${o.time}</td><td style="color:var(--cream);font-weight:500">${o.customer?esc(o.customer):'<span style="color:var(--border)">—</span>'}</td><td><span class="type-pill pill-${esc(o.type)}">${esc(o.type)}</span></td><td style="color:var(--cream-dim);max-width:230px;line-height:1.8">${o.items.map(i=>i.qty>1?`<b style="color:var(--cream)">${i.qty}×</b> ${esc(i.name)}`:esc(i.name)).join("<br>")}</td><td style="color:var(--cream);font-weight:500;text-align:center">${o.drinkCount}</td><td style="text-align:center"><button class="print-label-btn" onclick='printLabel(${JSON.stringify(o)})'>🖨 Print</button></td><td style="text-align:center"><button class="del-order-btn" onclick="deleteOrder(${o.num})">🗑 Delete</button></td></tr>`).join("");
  updateSortIcons();
}
function deleteOrder(num){
  const order = loadOrders().find(o=>o.num===num);
  if(!order)return;
  const label = order.customer ? `Order #${num} · ${order.customer}` : `Order #${num}`;
  document.getElementById("del-order-body").textContent = `Delete ${label}? This cannot be undone.`;
  document.getElementById("del-order-confirm-btn").onclick = ()=>{
    _ordersCache=_ordersCache.filter(o=>o.num!==num);
    deleteOrderFromDB(num).catch(e=>console.error("deleteOrder:",e));
    document.getElementById("del-order-modal").style.display="none";
    renderHistory();
    updateHeaderStats();
  };
  document.getElementById("del-order-modal").style.display="flex";
}
// ── Export / Import ───────────────────────────────────────────────────────────

function todayFilename(){
  const d=new Date();
  return "MotivationalMug_"+d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
}

function exportCSV(){
  const orders=loadOrders();
  if(!orders.length){alert("No orders to export.");return;}
  const rows=[["Order #","Date","Time","Customer","Type","Items","Drink Count"]];
  orders.forEach(o=>{
    const items=o.items.map(i=>{
      let s=i.name;
      if(i.unit) s=i.qty+" "+i.unit+"s "+i.name;
      else if(i.qty>1) s=i.qty+"x "+i.name;
      if(i.recipe&&i.recipe.length) s+=": "+i.recipe.map(r=>r.qty+(r.unit?r.unit[0]:"")+r.n).join(", ");
      return s;
    }).join(" | ");
    rows.push([o.num,o.date,o.time,o.customer||"",o.type,items,o.drinkCount]);
  });
  const csv=rows.map(r=>r.map(cell=>{
    const s=String(cell||"");
    return /[,"\n\r]/.test(s) ? '"'+s.replace(/"/g,'""')+'"' : s;
  }).join(",")).join("\n");
  downloadFile(todayFilename()+".csv","text/csv",csv);
}

function exportJSON(){
  const orders=loadOrders();
  if(!orders.length){alert("No orders to export.");return;}
  const backup={
    exported:new Date().toISOString(),
    version:2,
    nextOrderNum:loadNextNum(),
    orders
  };
  downloadFile(todayFilename()+"_backup.json","application/json",JSON.stringify(backup,null,2));
}

function downloadFile(filename,mime,content){
  const a=document.createElement("a");
  a.href=URL.createObjectURL(new Blob([content],{type:mime}));
  a.download=filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
}

function importJSON(input){
  const file=input.files[0];
  if(!file)return;
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const backup=JSON.parse(e.target.result);
      if(!backup.orders||!Array.isArray(backup.orders))
        throw new Error("Invalid backup file — no orders array found.");

      const existing=loadOrders();
      const existingNums=new Set(existing.map(o=>o.num));

      // Merge: only add orders not already present (by order number)
      const newOrders=backup.orders.filter(o=>!existingNums.has(o.num));
      const merged=[...existing,...newOrders].sort((a,b)=>a.num-b.num);

      _ordersCache=merged;
      // Save new orders to Supabase
      Promise.all(newOrders.map(o=>saveOrderToDB(o))).catch(e=>console.error("import:",e));

      // Update next order num if backup has higher numbers
      if(backup.nextOrderNum){
        const currentNext=loadNextNum();
        const maxInBackup=Math.max(...backup.orders.map(o=>o.num))+1;
        const newNext=Math.max(currentNext,backup.nextOrderNum,maxInBackup);
        _nextNumCache=newNext;
        bumpOrderNum(newNext).catch(e=>console.error("bumpNum:",e));
        updateOrderNumBadge();
      }

      // Show result
      const title=document.getElementById("import-modal-title");
      const body=document.getElementById("import-modal-body");
      title.textContent="Import Complete ✓";
      body.innerHTML=
        "<b>"+newOrders.length+"</b> new orders added.<br>"+
        "<b>"+(backup.orders.length-newOrders.length)+"</b> duplicates skipped (already in history).<br><br>"+
        "Total orders in history: <b>"+merged.length+"</b>";
      document.getElementById("import-modal").style.display="flex";

      renderHistory();
      updateHeaderStats();
    }catch(err){
      const title=document.getElementById("import-modal-title");
      const body=document.getElementById("import-modal-body");
      title.textContent="Import Failed";
      body.textContent="Could not read the file: "+err.message;
      document.getElementById("import-modal").style.display="flex";
    }
    input.value=""; // reset so same file can be reimported if needed
  };
  reader.readAsText(file);
}

function sortBy(col){sortDir=sortCol===col?(sortDir==="asc"?"desc":"asc"):"desc";sortCol=col;renderHistory();}
function updateSortIcons(){["num","date","time","customer","drinks"].forEach(c=>{const el=document.getElementById("si-"+c);if(el)el.textContent=sortCol===c?(sortDir==="asc"?"↑":"↓"):"↕";});}
function confirmClearAll(){document.getElementById("confirm-modal").style.display="flex"}
function closeConfirm(){document.getElementById("confirm-modal").style.display="none"}
function clearAllHistory(){_ordersCache=[];closeConfirm();renderHistory();updateHeaderStats();_clearAllOrdersDB().catch(e=>console.error("clearAll:",e));}
async function _clearAllOrdersDB(){const {error}=await supabase.from("orders").delete().neq("num",0);if(error)throw error;}
function renderEditorCats(){
  const list=document.getElementById("editor-cat-list");list.innerHTML="";
  Object.keys(MENU).forEach(cat=>{
    const btn=document.createElement("button");
    btn.className="editor-cat-btn"+(cat===editorCat?" active":"");
    btn.innerHTML=`<span style="flex:1;text-align:left;font-size:1rem;font-weight:700">${esc(cat)}</span><button class="editor-cat-del" onclick="event.stopPropagation();confirmDeleteCat('${esc2(cat)}')">✕</button>`;
    btn.onclick=()=>selectEditorCat(cat);list.appendChild(btn);
  });
  if(editorCat&&MENU[editorCat])renderEditorItems();
}
function selectEditorCat(cat){editorCat=cat;renderEditorCats();renderEditorItems();}
function renderEditorItems(){
  document.getElementById("editor-title").textContent=editorCat||"Select a category";
  const list=document.getElementById("editor-item-list");list.innerHTML="";
  if(!editorCat||!MENU[editorCat]){list.innerHTML='<div class="editor-empty">← Select a category</div>';return;}
  const items=MENU[editorCat];
  if(!items.length){list.innerHTML='<div class="editor-empty">No items yet — add one below</div>';return;}
  items.forEach((item,idx)=>{
    const it=mi(item);
    const row=document.createElement("div");row.className="editor-item";
    let meta="";
    if(it.dq&&it.unit)meta+=`<span class="editor-item-meta">${it.dq} ${it.unit}s default</span>`;
    if(it.recipe&&it.recipe.length)meta+=`<span class="editor-item-meta" style="color:var(--gold)">recipe: ${it.recipe.map(r=>r.qty+(r.unit?r.unit[0]:"")+r.n).join(", ")}</span>`;
    row.innerHTML=`<div style="flex:1;min-width:0"><span class="editor-item-name">${esc(it.n)}</span>${meta}</div><button class="edit-item-btn" onclick="openEditItem(${idx})">&#9999;&#65039; Edit</button><button class="del-item-btn" onclick="deleteItem(${idx})">Remove</button>`;
    list.appendChild(row);
  });
}
function addItem(){
  const input=document.getElementById("new-item-input"),val=input.value.trim();
  if(!val||!editorCat)return;
  const names=MENU[editorCat].map(i=>mi(i).n);
  if(!names.includes(val)){
    const isFlav=editorCat.includes("Flavor");
    MENU[editorCat].push(isFlav?{n:val,dq:3,unit:"pump"}:{n:val});
    saveMenu(MENU);buildCatSidebar();renderMenu();renderEditorItems();
  }
  input.value="";
}
function deleteItem(idx){if(!editorCat)return;MENU[editorCat].splice(idx,1);saveMenu(MENU);buildCatSidebar();renderMenu();renderEditorItems();}
function addCategory(){const input=document.getElementById("new-cat-input"),val=input.value.trim();if(!val||MENU[val])return;MENU[val]=[];saveMenu(MENU);editorCat=val;buildCatSidebar();renderEditorCats();renderEditorItems();input.value="";}
function confirmDeleteCat(cat){document.getElementById("del-cat-body").textContent=`Delete "${cat}" and all its items? This cannot be undone.`;document.getElementById("del-cat-confirm-btn").onclick=()=>deleteCategory(cat);document.getElementById("del-cat-modal").style.display="flex";}
function deleteCategory(cat){delete MENU[cat];saveMenu(MENU);if(editorCat===cat)editorCat=Object.keys(MENU)[0]||null;if(currentCat===cat)currentCat=Object.keys(MENU)[0]||"";document.getElementById("del-cat-modal").style.display="none";buildCatSidebar();renderMenu();renderEditorCats();renderEditorItems();}
let editIdx=-1;
function getAllRecipeItems(){
  // Returns all items across all categories that have a recipe
  const results=[];
  for(const[cat,items]of Object.entries(MENU)){
    for(const item of items){
      const it=mi(item);
      if(it.recipe&&it.recipe.length){
        results.push({cat,item:it});
      }
    }
  }
  return results;
}
function populateCopySelect(){
  const sel=document.getElementById("copy-recipe-select");
  if(!sel)return;
  const items=getAllRecipeItems();
  sel.innerHTML='<option value="">— Select an item with a recipe —</option>'+
    items.map((r,i)=>`<option value="${i}">${r.cat.replace(/[^\w\s]/g,"")} → ${r.item.n} (${r.item.recipe.length} ingredient${r.item.recipe.length!==1?"s":""})</option>`).join("");
  sel._items=items;
}
function copyRecipeFrom(){
  const sel=document.getElementById("copy-recipe-select");
  const idx=parseInt(sel.value);
  if(isNaN(idx)||!sel._items||!sel._items[idx])return;
  const source=sel._items[idx].item;
  // Deep copy recipe
  const copied=source.recipe.map(r=>Object.assign({},r));
  // Merge with existing rows (append) or replace?
  const existing=getRRs().filter(r=>r.n);
  if(existing.length>0){
    // Ask if they want to replace or append
    const choice=confirm("Replace existing ingredients with the copied recipe?\nClick OK to Replace, Cancel to Append.");
    renderRecipeRows(choice?copied:[...existing,...copied]);
  } else {
    renderRecipeRows(copied);
  }
  sel.value="";
}
function clearRecipe(){
  if(!getRRs().filter(r=>r.n).length)return;
  if(confirm("Clear all recipe ingredients?"))renderRecipeRows([]);
}
function openEditItem(idx){
  editIdx=idx;const it=mi(MENU[editorCat][idx]);
  document.getElementById("ei-name").value=it.n||"";
  document.getElementById("ei-dq").value=it.dq||1;
  document.getElementById("ei-unit").value=it.unit||"";
  renderRecipeRows(it.recipe||[]);
  document.getElementById("edit-item-modal").style.display="flex";
  populateCopySelect();
}
function closeEditItem(){document.getElementById("edit-item-modal").style.display="none";editIdx=-1;}
function renderRecipeRows(rows){
  const c=document.getElementById("recipe-rows");
  c.innerHTML=rows.map((r,i)=>`<div class="recipe-row"><input class="edit-field" placeholder="Ingredient name" value="${esc(r.n||r.name||"")}" id="rn${i}" style="flex:2;min-width:0"><input class="edit-field" type="number" min="1" value="${r.qty||1}" id="rq${i}" style="width:60px;flex-shrink:0"><input class="edit-field" placeholder="unit" value="${r.unit||""}" id="ru${i}" style="width:68px;flex-shrink:0"><button class="del-item-btn" onclick="removeRR(${i})" style="opacity:1;padding:4px 9px">&#x2715;</button></div>`).join("");
}
function addRR(){const rows=getRRs();rows.push({n:"",qty:1,unit:"pump"});renderRecipeRows(rows);}
function removeRR(i){const rows=getRRs();rows.splice(i,1);renderRecipeRows(rows);}
function getRRs(){const rows=[];let i=0;while(document.getElementById("rn"+i)){rows.push({n:document.getElementById("rn"+i).value.trim(),qty:parseInt(document.getElementById("rq"+i).value)||1,unit:document.getElementById("ru"+i).value.trim()});i++;}return rows;}
function saveEditItem(){
  if(editIdx<0||!editorCat)return;
  const name=document.getElementById("ei-name").value.trim();
  const dq=parseInt(document.getElementById("ei-dq").value)||1;
  const unit=document.getElementById("ei-unit").value.trim();
  const recipe=getRRs().filter(r=>r.n);
  if(!name){alert("Item name is required");return;}
  const item={n:name};
  if(dq>1||unit){item.dq=dq;if(unit)item.unit=unit;}
  if(recipe.length)item.recipe=recipe;
  MENU[editorCat][editIdx]=item;
  saveMenu(MENU);buildCatSidebar();renderMenu();renderEditorItems();closeEditItem();
}

// ── Wire renderHistory to async version ───────────────────────────────────────
// Override the sync renderHistory defined in the patched JS above
const _origRenderHistory = renderHistory;
window.renderHistory = function() { renderHistoryAsync(); };

// Helper: the actual DOM-building function (extracted from original renderHistory logic)
function _renderHistoryFromData(f, df) {
  f.sort((a,b)=>{let av,bv;if(sortCol==="num"){av=a.num;bv=b.num}else if(sortCol==="date"||sortCol==="time"){av=a.date+a.time;bv=b.date+b.time}else if(sortCol==="customer"){av=(a.customer||"").toLowerCase();bv=(b.customer||"").toLowerCase()}else if(sortCol==="drinks"){av=a.drinkCount;bv=b.drinkCount}else{av=a.num;bv=b.num}if(av<bv)return sortDir==="asc"?-1:1;if(av>bv)return sortDir==="asc"?1:-1;return 0;});
  const tots=f.length,drinks=f.reduce((s,o)=>s+o.drinkCount,0),mem=f.filter(o=>o.type==="Member").length,gue=f.filter(o=>o.type==="Guest").length,tog=f.filter(o=>o.type==="ToGo").length,days=new Set(f.map(o=>o.date)).size;
  document.getElementById("hist-summary").innerHTML=`<div class="hsum-card"><div class="hsum-n">${tots}</div><div class="hsum-l">Orders</div></div><div class="hsum-card"><div class="hsum-n">${drinks}</div><div class="hsum-l">Drinks</div></div><div class="hsum-card"><div class="hsum-n">${mem}</div><div class="hsum-l">Members</div></div><div class="hsum-card"><div class="hsum-n">${gue}</div><div class="hsum-l">Guests</div></div><div class="hsum-card"><div class="hsum-n">${tog}</div><div class="hsum-l">To Go</div></div>${!df?`<div class="hsum-card"><div class="hsum-n">${days}</div><div class="hsum-l">Days</div></div>`:""}`  ;
  const tbody=document.getElementById("history-tbody");
  if(!f.length){tbody.innerHTML=`<tr><td colspan="9" class="no-data">No orders found<br><span style="font-size:.78rem;color:var(--border)">Try a different date or filter</span></td></tr>`;updateSortIcons();return;}
  tbody.innerHTML=f.map(o=>`<tr><td style="color:var(--gold);font-weight:600">#${o.num}</td><td style="white-space:nowrap">${fmtDate(o.date)}</td><td style="white-space:nowrap;color:var(--muted)">${o.time}</td><td style="color:var(--cream);font-weight:500">${o.customer?esc(o.customer):'<span style="color:var(--border)">—</span>'}</td><td><span class="type-pill pill-${esc(o.type)}">${esc(o.type)}</span></td><td style="color:var(--cream-dim);max-width:230px;line-height:1.8">${o.items.map(i=>i.qty>1?`<b style="color:var(--cream)">${i.qty}×</b> ${esc(i.name)}`:esc(i.name)).join("<br>")}</td><td style="color:var(--cream);font-weight:500;text-align:center">${o.drinkCount}</td><td style="text-align:center"><button class="print-label-btn" onclick='printLabel(${JSON.stringify(o)})'>🖨 Print</button></td><td style="text-align:center"><button class="del-order-btn" onclick="deleteOrder(${o.num})">🗑 Delete</button></td></tr>`).join("");
  updateSortIcons();
}

